     1→const rule = {
     2→	meta: {
     3→		type: 'suggestion',
     4→		docs: {
     5→			description: 'Require custom functions to use single object parameter',
     6→			category: 'Best Practices',
     7→		},
     8→		schema: [],
     9→		messages: {
    10→			requireObjectParam:
    11→				'Custom functions must use a single object destructuring parameter',
    12→		},
    13→	},
    14→	create(context) {
    15→		const lifecycleHooks = [
    16→			'onModuleInit',
    17→			'onApplicationBootstrap',
    18→			'onModuleDestroy',
    19→			'onApplicationShutdown',
    20→			'configure',
    21→			'use',
    22→			'catch',
    23→			'intercept',
    24→			'canActivate',
    25→			'validate',
    26→			'transform',
    27→			'run',
    28→		];
    29→
    30→		const testingCallbacks = [
    31→			'it',
    32→			'test',
    33→			'describe',
    34→			'beforeEach',
    35→			'afterEach',
    36→			'beforeAll',
    37→			'afterAll',
    38→		];
    39→
    40→		const nestjsDecorators = [
    41→			'Get',
    42→			'Post',
    43→			'Put',
    44→			'Delete',
    45→			'Patch',
    46→			'Options',
    47→			'Head',
    48→			'All',
    49→			'UseGuards',
    50→			'UseInterceptors',
    51→			'UsePipes',
    52→			'SetMetadata',
    53→			'Option',
    54→			'CronJobExecution',
    55→		];
    56→
    57→		const explicitSkipFunctions = ['transform'];
    58→
    59→		function hasNestJSDecorator(node) {
    60→			const parent = node.parent;
    61→			if (parent?.type === 'MethodDefinition' && parent.decorators) {
    62→				return parent.decorators.some((decorator) => {
    63→					const dec = decorator;
    64→					if (dec.expression.type === 'CallExpression') {
    65→						const callExpr = dec.expression;
    66→						const callee = callExpr.callee;
    67→						if (callee.type === 'Identifier') {
    68→							return nestjsDecorators.includes(callee.name);
    69→						}
    70→					}
    71→					return false;
    72→				});
    73→			}
    74→			return false;
    75→		}
    76→
    77→		function isFrameworkMethod(node) {
    78→			const parent = node.parent;
    79→
    80→			if (parent?.type === 'MethodDefinition') {
    81→				if (parent.kind === 'constructor') {
    82→					return true;
    83→				}
    84→
    85→				const key = parent.key;
    86→				if (key?.type === 'Identifier' && lifecycleHooks.includes(key.name)) {
    87→					return true;
    88→				}
    89→
    90→				if (hasNestJSDecorator(node)) {
    91→					return true;
    92→				}
    93→			}
    94→
    95→			return false;
    96→		}
    97→
    98→		function isTestingCallback(node) {
    99→			const parent = node.parent;
   100→
   101→			if (parent?.type === 'CallExpression') {
   102→				const callee = parent.callee;
   103→				if (callee.type === 'Identifier' && testingCallbacks.includes(callee.name)) {
   104→					return true;
   105→				}
   106→			}
   107→
   108→			return false;
   109→		}
   110→
   111→		function isCallbackFunction(node) {
   112→			const parent = node.parent;
   113→
   114→			if (!parent) return false;
   115→
   116→			if (isTestingCallback(node)) {
   117→				return true;
   118→			}
   119→
   120→			if (parent.type === 'CallExpression' || parent.type === 'NewExpression') {
   121→				const callExpr = parent;
   122→				if (callExpr.arguments.some((arg) => arg === node)) {
   123→					return true;
   124→				}
   125→			}
   126→
   127→			if (parent.type === 'ArrayExpression') {
   128→				return true;
   129→			}
   130→
   131→			if (parent.type === 'Property') {
   132→				const prop = parent;
   133→				if (prop.value === node) {
   134→					const grandParent = prop.parent;
   135→					if (grandParent?.type === 'ObjectExpression') {
   136→						const greatGrandParent = grandParent.parent;
   137→						if (greatGrandParent?.type === 'CallExpression') {
   138→							return true;
   139→						}
   140→					}
   141→				}
   142→			}
   143→
   144→			return false;
   145→		}
   146→
   147→		function checkFunction(node) {
   148→			if (isCallbackFunction(node) || isFrameworkMethod(node)) {
   149→				return;
   150→			}
   151→
   152→			const funcName =
   153→				node.id?.name ??
   154→				(node.parent?.type === 'MethodDefinition' ? node.parent.key?.name : undefined);
   155→
   156→			if (funcName && explicitSkipFunctions.includes(funcName)) {
   157→				return;
   158→			}
   159→
   160→			const params = node.params;
   161→
   162→			if (params.length === 0) {
   163→				return;
   164→			}
   165→
   166→			if (params.length === 1 && params[0]?.type === 'RestElement') {
   167→				return;
   168→			}
   169→
   170→			if (params.length === 1 && params[0]?.type === 'AssignmentPattern') {
   171→				return;
   172→			}
   173→
   174→			const hasValidObjectParam =
   175→				params.length === 1 && params[0]?.type === 'ObjectPattern';
   176→
   177→			if (!hasValidObjectParam) {
   178→				context.report({
   179→					node: node,
   180→					messageId: 'requireObjectParam',
   181→				});
   182→			}
   183→		}
   184→
   185→		return {
   186→			FunctionDeclaration(node) {
   187→				checkFunction(node);
   188→			},
   189→			FunctionExpression(node) {
   190→				const funcNode = node;
   191→				if (funcNode.parent?.type === 'MethodDefinition') {
   192→					return;
   193→				}
   194→				checkFunction(funcNode);
   195→			},
   196→			ArrowFunctionExpression(node) {
   197→				checkFunction(node);
   198→			},
   199→			MethodDefinition(node) {
   200→				const methodNode = node;
   201→				checkFunction(methodNode.value);
   202→			},
   203→		};
   204→	},
   205→};
   206→
   207→module.exports = rule;
   208→

