   126→export function validate({
   127→	envConfig,
   128→}: {
   129→	envConfig: Record<string, unknown>;
   130→}): EnvironmentVariables {
   131→	const logger = Logger;
   132→	const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
   133→		enableImplicitConversion: true,
   134→	});
   135→
   136→	const errors = validateSync(validatedConfig, {
   137→		skipMissingProperties: false,
   138→		forbidUnknownValues: true,
   139→		stopAtFirstError: true,
   140→		forbidNonWhitelisted: true,
   141→	});
   142→
   143→	if (errors.length > 0) {
   144→		logger.error('Config validation error', errors);
   145→		throw new Error(errors.toString());
   146→	}
   147→
   148→	return validatedConfig;
   149→}
