import { Logger, ValidationPipe } from '@nestjs/common';
import { NestFactory } from '@nestjs/core';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { FastifyRequest, FastifyReply } from 'fastify';

import { RecoConsoleLogger } from '@config/custom-logger.config';
import { bufferedRollbar } from '@config/rollbar-buffer.config';

import { AppModule } from '@modules/app/app.module';
import { NewrelicService } from '@modules/newrelic/newrelic.service';

import { getEnv } from '@utils/get-env-variable.util';
import { setupSwagger } from '@utils/setup-swagger.util';

import { BadRequestExceptionFilter } from '@middlewares/bad-request-exception.filter';
import { CorrelationIdMiddleware } from '@middlewares/correlation-id.middleware';
import { RollbarExceptionFilter } from '@middlewares/exceptions.filter';
import { fastifyHttpLogger } from '@middlewares/logger.middleware';

import {
	NODE_ENV,
	PORT,
	SERVER_NAME,
	GLOBAL_PREFIX,
	IS_COMPACT_LOGS,
	IS_JSON_LIKE_LOGS,
} from '@constants/env-variables.constant';

import { Environment } from '@interfaces/env-variables.interface';

import { NewrelicInterceptor } from '@interceptors/newrelic.interceptor';

declare const module: {
	hot?: { accept: () => void; dispose: (callback: () => void) => void };
};

async function bootstrap(): Promise<NestFastifyApplication> {
	const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
	const port = getEnv<number>({ key: PORT, converter: Number });
	const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
	const serverName = getEnv<string>({ key: SERVER_NAME });
	const isCompactLogs = getEnv<boolean>({ key: IS_COMPACT_LOGS, converter: Boolean });
	const isJsonLikeLogs = getEnv<boolean>({ key: IS_JSON_LIKE_LOGS, converter: Boolean });
	const isDev = nodeEnv === Environment.DEVELOPMENT;
	const isProdOrStaging =
		nodeEnv === Environment.PRODUCTION || nodeEnv === Environment.STAGING;

	const logger = new RecoConsoleLogger({
		logLevels: isDev
			? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
			: ['log', 'error', 'warn', 'fatal'],
		colors: isDev,
		prefix: serverName,
		compact: isCompactLogs,
		json: isJsonLikeLogs,
	});

	const fastifyAdapter = new FastifyAdapter({
		trustProxy: true,
	});
	fastifyAdapter.getInstance().register(fastifyHttpLogger);

	const app = await NestFactory.create<NestFastifyApplication>(
		AppModule,
		fastifyAdapter,
		{ bodyParser: false, rawBody: true, logger },
	);

	if (nodeEnv !== Environment.PRODUCTION) {
		setupSwagger({ app, fastifyAdapter, globalPrefix });
	}

	app.enableCors({ origin: true, credentials: true });

	app.use((req: FastifyRequest['raw'], res: FastifyReply['raw'], next: () => void) => {
		const middleware = new CorrelationIdMiddleware();
		middleware.use(req, res, next);
	});

	if (isProdOrStaging) {
		app.useGlobalInterceptors(
			new NewrelicInterceptor(await app.resolve<NewrelicService>(NewrelicService)),
		);
		app.useGlobalFilters(new RollbarExceptionFilter());
	}

	app.useGlobalFilters(new BadRequestExceptionFilter());

	app.useGlobalPipes(
		new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
	);

	app.setGlobalPrefix(globalPrefix, {
		exclude: ['is_it_up', 'is_it_working', 'is_it_ready', 'robots.txt'],
	});

	if (!isDev) {
		app.enableShutdownHooks();
	}

	logger.log(`[Main file] Application is running on ${String(port)} port`);
	await app.listen(port, '0.0.0.0');

	if (!isDev) {
		const LogShutDown = ({ signal }: { signal: string }): void => {
			logger.log(`Received ${signal} server is shutting down`);
		};
		process.on('SIGINT', () => {
			LogShutDown({ signal: 'SIGINT' });
		});
		process.on('SIGTERM', () => {
			LogShutDown({ signal: 'SIGTERM' });
		});
	}

	return app;
}

let app: NestFastifyApplication | undefined;

async function startApp(): Promise<void> {
	try {
		app = await bootstrap();
	} catch (err: unknown) {
		Logger.flush();
		bufferedRollbar.critical({ err: err as Error });
		void bufferedRollbar.wait().then(() => process.exit(1));
	}
}

void startApp();

if (module.hot) {
	module.hot.accept();
	module.hot.dispose(() => {
		void app?.close();
	});
}
