import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';

@Injectable()
export class EnvConfigService {
	private readonly logger = new Logger(EnvConfigService.name);

	constructor(private readonly configService: ConfigService) {}

	get<T = unknown>({
		key,
		converter,
	}: {
		key: string;
		converter?: (param: unknown) => T;
	}): T {
		this.logger.log(
			`Fetching environment variable: ${key}, converter: ${converter ? converter.name : 'none'}`,
		);
		const envVariable = this.configService.get<T>(key);

		if (envVariable === undefined) {
			throw new Error(`Environment variable ${key} is not defined`);
		}

		return converter ? converter(envVariable) : envVariable;
	}
}
