	NEWRELIC_KEY: process.env['NEWRELIC_KEY'],
	AWS_REGION: process.env['AWS_REGION'],
	ROLLBAR_ACCESS_TOKEN: process.env['ROLLBAR_ACCESS_TOKEN'],
	OPENAI_API_KEY: process.env['OPENAI_API_KEY'],
	MMS_INTERNAL_BASE_URL: process.env['MMS_INTERNAL_BASE_URL'],
	ARTILLERY_KEY: process.env['ARTILLERY_KEY'],
	RELATED_PRODUCTS_CACHE_TTL: process.env['RELATED_PRODUCTS_CACHE_TTL'],
	CI_BASE_URL: process.env['CI_BASE_URL'],
	DATABASE_URL_READ_REPLICA: process.env['DATABASE_URL_READ_REPLICA'],
	DATABASE_URL: process.env['DATABASE_URL'],
	MMS_IMAGES_LAMBDA_HOST: process.env['MMS_IMAGES_LAMBDA_HOST'],
	ALG_FBT_INDEX_NAME: process.env['ALG_FBT_INDEX_NAME'],
	EXECUTION_TIME_THRESHOLD_MS: process.env['EXECUTION_TIME_THRESHOLD_MS'],
	CURATED_ADDONS_CACHE_TTL: process.env['CURATED_ADDONS_CACHE_TTL'],
	BIGQUERY_SERVICE_ACCOUNT_KEY: process.env['BIGQUERY_SERVICE_ACCOUNT_KEY'],
});

export const loadEnvVariables = (): ConfigFactory[] => {
	if (isStagingEnv() || isProdEnv()) {
		validate({ envConfig: getEnvVariables() });
		return [getEnvVariables];
	}

	const envFilePath = path.resolve(process.cwd(), getEnvFile());

	if (!fs.existsSync(envFilePath)) {
		return [() => ({})];
	}

	const envConfig = dotenv.parse(fs.readFileSync(envFilePath));

	validate({ envConfig });

	return [() => envConfig];
};
